// ============================================================
// stm32_gpio.hpp — STM32F4 GPIO Driver (C++ HAL wrapper)
// Case Study 5 for "Claude Code + C++ Software Design" paper
// Generated by Claude Code, reviewed and revised by 赵鑫
//
// Tests Claude Code's limits on:
//   - Low-level register access (volatile, memory-mapped I/O)
//   - Hardware Abstraction Layer (HAL) design
//   - Interrupt safety (ISR context awareness)
//   - RAII for peripheral resource management
//   - Bit-field manipulation patterns
//
// TARGET: STM32F407VG (Cortex-M4)
// Compiler: arm-none-eabi-g++ 13.2
// ============================================================

#pragma once

#include <cstdint>
#include <type_traits>
#include <cassert>

// ============================================================
// Simulated Memory-Mapped Register Base Addresses
// In real firmware, these come from the CMSIS device header.
// We define them here for portability across test environments.
// ============================================================

// [CLAUDE CODE NOTE]: Claude Code v1 generated these as global
// constexpr pointers, which is undefined behavior in C++ — you
// cannot dereference an arbitrary integer as a pointer. Manual
// fix by 赵鑫: use reinterpret_cast with volatile, and wrap in
// inline accessor functions. (2 iterations)
namespace cccs::stm32 {

inline constexpr uintptr_t GPIOA_BASE = 0x40020000;
inline constexpr uintptr_t GPIOB_BASE = 0x40020400;
inline constexpr uintptr_t GPIOC_BASE = 0x40020800;
inline constexpr uintptr_t RCC_BASE   = 0x40023800;

// RCC registers (simplified)
inline constexpr uintptr_t RCC_AHB1ENR = RCC_BASE + 0x30;

// ============================================================
// GPIO Register Offsets
// ============================================================
enum class GPIORegister : uint32_t {
    MODER   = 0x00,  // Mode register
    OTYPER  = 0x04,  // Output type register
    OSPEEDR = 0x08,  // Output speed register
    PUPDR   = 0x0C,  // Pull-up/pull-down register
    IDR     = 0x10,  // Input data register
    ODR     = 0x14,  // Output data register
    BSRR    = 0x18,  // Bit set/reset register
    AFRL    = 0x20,  // Alternate function low
    AFRH    = 0x24,  // Alternate function high
};

// ============================================================
// GPIO Pin Mode
// ============================================================
enum class GPIOMode : uint32_t {
    Input     = 0x0,
    Output    = 0x1,
    Alternate = 0x2,
    Analog    = 0x3,
};

enum class GPIOOutputType : uint32_t {
    PushPull  = 0x0,
    OpenDrain = 0x1,
};

enum class GPIOSpeed : uint32_t {
    Low      = 0x0,
    Medium   = 0x1,
    Fast     = 0x2,  // [CLAUDE CODE BUG]: Claude Code v1 generated "High" = 0x2
                      // but STM32 TRM defines 0x3 as "High". Fixed by 赵鑫.
    High     = 0x3,
};

enum class GPIOPull : uint32_t {
    None     = 0x0,
    PullUp   = 0x1,
    PullDown = 0x2,
};

// ============================================================
// GPIO Pin abstraction
// ============================================================
class GPIOPin {
public:
    // [HUMAN FIX 2025-07-08]: Replaced broken static_assert with runtime assert.
    // In NDEBUG builds (production), assert compiles to a no-op and the
    // caller bears responsibility for passing a valid pin (0-15).
    GPIOPin(uint8_t pin_number) noexcept
        : pin_(pin_number)
    {
        assert(pin_number <= 15 && "STM32 GPIO pin must be 0-15");
    }

    [[nodiscard]] constexpr uint8_t value() const noexcept { return pin_; }
    [[nodiscard]] constexpr uint32_t mask() const noexcept {
        return 1u << pin_;
    }

private:
    uint8_t pin_;
};

// ============================================================
// Register Access Helper (volatile-aware)
// ============================================================
namespace detail {
    inline volatile uint32_t& reg(uintptr_t base, GPIORegister offset) {
        return *reinterpret_cast<volatile uint32_t*>(base + static_cast<uint32_t>(offset));
    }

    // Atomic bit-set via BSRR — hardware guarantees atomicity
    inline void atomic_set(uintptr_t base, uint32_t mask) {
        reg(base, GPIORegister::BSRR) = mask;
    }

    // Atomic bit-reset via BSRR (upper 16 bits = reset)
    inline void atomic_reset(uintptr_t base, uint32_t mask) {
        reg(base, GPIORegister::BSRR) = (mask << 16);
    }
}

// ============================================================
// GPIO Port — RAII wrapper for a GPIO bank (A, B, C, ...)
// ============================================================
class GPIOPort {
public:
    explicit GPIOPort(uintptr_t base_address) noexcept
        : base_(base_address) {}

    // Non-copyable, movable
    GPIOPort(const GPIOPort&) = delete;
    GPIOPort& operator=(const GPIOPort&) = delete;
    GPIOPort(GPIOPort&& other) noexcept : base_(other.base_) {
        other.base_ = 0;
    }
    GPIOPort& operator=(GPIOPort&&) = delete;  // register state not transferable

    // ---- Configuration ----
    void configure_pin(GPIOPin pin, GPIOMode mode, GPIOPull pull = GPIOPull::None,
                       GPIOSpeed speed = GPIOSpeed::Low,
                       GPIOOutputType otype = GPIOOutputType::PushPull) noexcept
    {
        uint32_t p = pin.value();
        uint32_t moder   = detail::reg(base_, GPIORegister::MODER);
        uint32_t otyper  = detail::reg(base_, GPIORegister::OTYPER);
        uint32_t ospeedr = detail::reg(base_, GPIORegister::OSPEEDR);
        uint32_t pupdr   = detail::reg(base_, GPIORegister::PUPDR);

        // Clear and set MODER (2 bits per pin)
        moder   = (moder   & ~(0x3u << (p * 2))) |
                  (static_cast<uint32_t>(mode) << (p * 2));
        // Clear and set OTYPER (1 bit per pin)
        otyper  = (otyper  & ~(0x1u << p)) |
                  (static_cast<uint32_t>(otype) << p);
        // Clear and set OSPEEDR (2 bits per pin)
        ospeedr = (ospeedr & ~(0x3u << (p * 2))) |
                  (static_cast<uint32_t>(speed) << (p * 2));
        // Clear and set PUPDR (2 bits per pin)
        pupdr   = (pupdr   & ~(0x3u << (p * 2))) |
                  (static_cast<uint32_t>(pull) << (p * 2));

        detail::reg(base_, GPIORegister::MODER)   = moder;
        detail::reg(base_, GPIORegister::OTYPER)  = otyper;
        detail::reg(base_, GPIORegister::OSPEEDR) = ospeedr;
        detail::reg(base_, GPIORegister::PUPDR)   = pupdr;
    }

    // ---- Output operations (thread-safe via BSRR) ----
    void set_pin(GPIOPin pin) noexcept {
        detail::atomic_set(base_, pin.mask());
    }

    void reset_pin(GPIOPin pin) noexcept {
        detail::atomic_reset(base_, pin.mask());
    }

    void toggle_pin(GPIOPin pin) noexcept {
        uint32_t odr = detail::reg(base_, GPIORegister::ODR);
        if (odr & pin.mask()) {
            detail::atomic_reset(base_, pin.mask());
        } else {
            detail::atomic_set(base_, pin.mask());
        }
    }

    // ---- Input operations ----
    [[nodiscard]] bool read_pin(GPIOPin pin) const noexcept {
        return (detail::reg(base_, GPIORegister::IDR) & pin.mask()) != 0;
    }

    [[nodiscard]] uint32_t read_port() const noexcept {
        return detail::reg(base_, GPIORegister::IDR);
    }

    // ---- Port management ----
    void reset_port() noexcept {
        // Reset all pins to low
        detail::reg(base_, GPIORegister::BSRR) = 0xFFFF0000u;
    }

    void enable_clock() noexcept {
        // Set the appropriate RCC AHB1ENR bit
        uint32_t bit = 0;
        if (base_ == GPIOA_BASE) bit = 0;
        else if (base_ == GPIOB_BASE) bit = 1;
        else if (base_ == GPIOC_BASE) bit = 2;

        // [FIXED 2025-07-08]: Use RCC_AHB1ENR address directly.
        // Previously used RCC_BASE + MODER offset (0x40023800), which
        // is the wrong register — RCC_AHB1ENR is at 0x40023830.
        volatile uint32_t& rcc = *reinterpret_cast<volatile uint32_t*>(RCC_AHB1ENR);
        // (simplified: in production, use CMSIS __HAL_RCC_GPIOx_CLK_ENABLE)
        rcc = rcc | (1u << bit);
        __asm__ volatile("dmb sy");  // Data Memory Barrier for Cortex-M
    }

    [[nodiscard]] uintptr_t base_address() const noexcept { return base_; }

private:
    uintptr_t base_;
};

// ============================================================
// GPIO Manager — owns all GPIO ports (RAII at chip level)
// ============================================================
class GPIOManager {
public:
    GPIOManager() noexcept
        : port_a_(GPIOA_BASE)
        , port_b_(GPIOB_BASE)
        , port_c_(GPIOC_BASE)
    {
        // Enable all GPIO clocks at startup
        port_a_.enable_clock();
        port_b_.enable_clock();
        port_c_.enable_clock();
    }

    ~GPIOManager() noexcept {
        port_a_.reset_port();
        port_b_.reset_port();
        port_c_.reset_port();
    }

    GPIOPort& port_a() noexcept { return port_a_; }
    GPIOPort& port_b() noexcept { return port_b_; }
    GPIOPort& port_c() noexcept { return port_c_; }

private:
    GPIOPort port_a_;
    GPIOPort port_b_;
    GPIOPort port_c_;
};

} // namespace cccs::stm32
